const Q_IRK_1992=[{"id": "objective>IRK>1992>1", "question": "<div style=\"font-family:Cambria;font-size:17px;\">'La yukallifu Hahu nafsan illa wus aha'  <br/> This quotation is part of </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Surat al-Alaq</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Surat al-A la</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Ayat al-Kuray</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Ayat Amanar- Rasul</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">'La yukallifu Hahu nafsan illa wus aha'  <br/> This quotation is part of Ayat Amanar- Rasul.</div>", "topic": "STUDY OF THE ARABIC TEXT OF THE FOLLOWING SUWAR/AYATS WITH TAJWID : AL-ALAQ~~STUDY OF THE ARABIC TEXT OF THE FOLLOWING SUWAR/AYATS WITH TAJWID : AL-A'ALA~~STUDY OF THE ARABIC TEXT OF THE FOLLOWING SUWAR/AYATS WITH TAJWID : AYATUL-KURSIY~~STUDY OF THE ARABIC TEXT OF THE FOLLOWING SUWAR/AYATS WITH TAJWID : AMANAR-RASUL"}, {"id": "objective>IRK>1992>2", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Surely, we created man of the best stature. Then we reduced him to the lowest of the low, save those who believe and do good works'.  <br/> This quotation is from Surat</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">al Asr</div>", "<div style=\"font-family:Cambria;font-size:17px;\">al-Alaq</div>", "<div style=\"font-family:Cambria;font-size:17px;\">al-Tin</div>", "<div style=\"font-family:Cambria;font-size:17px;\">al-Boyyinoh</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The quotation 'Surely, we created man of the best stature. Then we reduced him to the lowest of the low, save those who believe and do good works' is from Surat al-Tin (The Fig). This Surah discusses the creation of human beings and their ultimate fate.</div>", "topic": "STUDY OF THE ARABIC TEXT OF THE FOLLOWING SUWAR/AYATS WITH TAJWID : AT-TIN"}, {"id": "objective>IRK>1992>3", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The memorization, recording and compilation of the Quran ensured its </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">divine nature </div>", "<div style=\"font-family:Cambria;font-size:17px;\">divine authority</div>", "<div style=\"font-family:Cambria;font-size:17px;\">authenticity</div>", "<div style=\"font-family:Cambria;font-size:17px;\">eternity</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The memorization, recording, and compilation of the Quran ensured its authenticity. The Quran was revealed to Prophet Muhammad who memorized it and then it was written down by his companions. This process ensured that the Quran remained authentic and unchanged.</div>", "topic": "PROOF OF THE DIVINE AUTHENTICITY OF THE GLORIOUS QUR'AN : DIVINE PRESERVATION OF THE GLORIOUS QUR'AN"}, {"id": "objective>IRK>1992>4", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> <span style=\"font-style:italic;\"> 'Inna ma yurida ash-shaytanu an yuqi a baynakumul- adawata wal-baghda fil khamr wal-maysir' </span> (Q. 5:91) <br/> The verse quoted above enumerates the evils of </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">wine and adultery</div>", "<div style=\"font-family:Cambria;font-size:17px;\">gambling and adultery</div>", "<div style=\"font-family:Cambria;font-size:17px;\">adultery and divining arrows </div>", "<div style=\"font-family:Cambria;font-size:17px;\">wine and gambling</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The verse quoted above enumerates the evils of wine.</div>", "topic": "MORAL LESSONS IN THE GLORIOUS QUR’AN AND HADITH : PROHIBITION OF BRIBERY AND CORRUPTION (Q:2:188), ALCOHOL AND GAMBLING (Q.2:219) (Q.5:93-94), STEALING AND FRAUD (Q.5:41) (83:1-5),SMOKING, DRUG ABUSE AND OTHER INTOXICANTS (Q.2:172-173, 195 AND 219) (Q.4:43) (Q.5:3) (Q.6:118-121) ARROGANCE (Q.31:18-19) AND EXTRAVAGANCE (Q.17:26-27) (Q.31:18-19)"}, {"id": "objective>IRK>1992>5", "question": "<div style=\"font-family:Cambria;font-size:17px;\">One of the strong proofs of the authenticity of the Quran is that </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">the like of it has not been produced by an individual or a group of people </div>", "<div style=\"font-family:Cambria;font-size:17px;\">the Arabic language in which it was revealed is still spoken</div>", "<div style=\"font-family:Cambria;font-size:17px;\">it was compiled soon after its revelation </div>", "<div style=\"font-family:Cambria;font-size:17px;\">it has been translated into many languages </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">One of the strong proofs of the authenticity of the Quran is that the like of it has not been produced by an individual or a group of people. This is a challenge that the Quran itself puts forth in Surah Al-Baqarah (2:23) where it states 'And if you are in doubt about what We have sent down upon Our Servant [Muhammad], then produce a surah the like thereof and call upon your witnesses other than Allah, if you should be truthful.'</div>", "topic": "PROOF OF THE DIVINE AUTHENTICITY OF THE GLORIOUS QUR'AN : UNIQUENESS OF THE GLORIOUS QUR'AN"}, {"id": "objective>IRK>1992>6", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In Islam, intoxicants are </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">forbidden even in small quantity</div>", "<div style=\"font-family:Cambria;font-size:17px;\">allowed only in small quantity</div>", "<div style=\"font-family:Cambria;font-size:17px;\">tolerated only during celebrations </div>", "<div style=\"font-family:Cambria;font-size:17px;\">left to personal decision</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In Islam, intoxicants are forbidden even in small quantity. This is based on several Hadiths (sayings of Prophet Muhammad) and verses from the Quran that prohibit the consumption of intoxicants due to their harmful effects on the individual and society.</div>", "topic": "MORAL LESSONS IN THE GLORIOUS QUR’AN AND HADITH : PROHIBITION OF BRIBERY AND CORRUPTION (Q:2:188), ALCOHOL AND GAMBLING (Q.2:219) (Q.5:93-94), STEALING AND FRAUD (Q.5:41) (83:1-5),SMOKING, DRUG ABUSE AND OTHER INTOXICANTS (Q.2:172-173, 195 AND 219) (Q.4:43) (Q.5:3) (Q.6:118-121) ARROGANCE (Q.31:18-19) AND EXTRAVAGANCE (Q.17:26-27) (Q.31:18-19)"}, {"id": "objective>IRK>1992>7", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The Qura'nic verse  <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> (31:18) <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> teaches against </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">adultery</div>", "<div style=\"font-family:Cambria;font-size:17px;\">infanticide </div>", "<div style=\"font-family:Cambria;font-size:17px;\">bribery</div>", "<div style=\"font-family:Cambria;font-size:17px;\">arrogance </div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The Qura'nic verse  31:18 teaches against arrogance.</div>", "topic": "MORAL LESSONS IN THE GLORIOUS QUR’AN AND HADITH : ARROGANCE (Q.31:18-19) AND EXTRAVAGANCE (Q.17:26-27) (Q.31:18-19)"}, {"id": "objective>IRK>1992>8", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> <span style=\"font-style:italic;\"> 'wa lam yakun lahu kufuwan ahad' </span> <br/> This verse of the Quran (112:4) says that Allah</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">is childless </div>", "<div style=\"font-family:Cambria;font-size:17px;\">is unique </div>", "<div style=\"font-family:Cambria;font-size:17px;\">has no parents </div>", "<div style=\"font-family:Cambria;font-size:17px;\">has no favourites </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Qur'an 112:4 says: <br/>  <br/> \"Wa lam yakun lahu kufuwan aḥad.\" <br/> \"And there is none comparable to Him.\"</div>", "topic": "TAWHID AND FIQH : KALIMATUSH-SHAHADAH"}, {"id": "objective>IRK>1992>9", "question": "<div style=\"font-family:Cambria;font-size:17px;\">'God was well pleased with the believers when they pledged all allegiance unto thee beneath the tree'. <br/> This verse was revealed in connection with the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">battle of Badr</div>", "<div style=\"font-family:Cambria;font-size:17px;\">battle of Tabuk</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Treaty of Hudaybiyah</div>", "<div style=\"font-family:Cambria;font-size:17px;\">pledge of Aqabah</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">This verse was revealed in connection with the pledge of Aqabah.</div>", "topic": "THE LIFE OF PROPHET MUHAMMAD (SAW) : THE TREATY OF AL-HUDAIBIYYAH AND THE CONQUEST OF MAKKAH"}, {"id": "objective>IRK>1992>10", "question": "<div style=\"font-family:Cambria;font-size:17px;\">From which chapter of the Quran is the verse which declares 'Certainly, we created man in the best make'?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">87</div>", "<div style=\"font-family:Cambria;font-size:17px;\">95</div>", "<div style=\"font-family:Cambria;font-size:17px;\">97</div>", "<div style=\"font-family:Cambria;font-size:17px;\">99</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The verse 'Certainly, we created man in the best make' is from Surah At-Tin (The Fig), which is the 95th chapter of the Quran. This verse is a reflection of the Islamic belief in the inherent goodness and dignity of human beings.</div>", "topic": "THE QUR'AN AND HADITH – REVELATION OF THE GLORIOUS QUR’AN"}, {"id": "objective>IRK>1992>11", "question": "<div style=\"font-family:Cambria;font-size:17px;\">To maintain the quality of <span style=\"font-style:italic;\"> Taqwa </span> one has to be </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">wealthy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">disciplined </div>", "<div style=\"font-family:Cambria;font-size:17px;\">poor </div>", "<div style=\"font-family:Cambria;font-size:17px;\">a leader</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Taqwa is an Islamic term for being conscious and cognizant of Allah, of truth, of the rational reality, 'piety, fear of God'. It is often found in the Quran. To maintain the quality of Taqwa, one has to be disciplined. It is not about wealth, poverty, or leadership, but about a person's inner state and their actions.</div>", "topic": "TAWHID AND FIQH : FAITH"}, {"id": "objective>IRK>1992>12", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Sahih al-Bukhari is regarded as the most authenti collection of Hadith because its collector was </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">older than any other collector of Hadith</div>", "<div style=\"font-family:Cambria;font-size:17px;\">alive during the time of the Prophet (S.A.W.)</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the most critical of the collectors </div>", "<div style=\"font-family:Cambria;font-size:17px;\">a founder of a school of law </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Sahih al-Bukhari is regarded as the most authentic collection of Hadith because its collector, Imam Bukhari, was the most critical of the collectors. He established strict criteria for the acceptance of a Hadith, including the soundness of the chain of narrators and the consistency of the narration with other established facts.</div>", "topic": "HADITH : AUTHENTICATION OF HADITH"}, {"id": "objective>IRK>1992>13", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Musnad is a collection of ahadith arranged </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">according to the names of the authorities </div>", "<div style=\"font-family:Cambria;font-size:17px;\">into chapters dealing with specific topics </div>", "<div style=\"font-family:Cambria;font-size:17px;\">according to word-endings </div>", "<div style=\"font-family:Cambria;font-size:17px;\">in alphabetical order</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Musnad is a collection of ahadith arranged according to the names of the authorities. This means that the ahadith are grouped by the name of the companion of the Prophet who narrated them. This is different from other collections which may be arranged by topic or other criteria.</div>", "topic": "HADITH : HISTORY OF HADITH LITERATURE -COLLECTION OF HADITH FROM THE TIME OF THE PROPHET-SAW TO THE PERIOD OF THE SIX AUTHENTIC COLLECTORS OF HADITH"}, {"id": "objective>IRK>1992>14", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Part of the 23rd Hadith of al-Nawawi's collection refers to purification as a </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">half of faith</div>", "<div style=\"font-family:Cambria;font-size:17px;\">shining of glory</div>", "<div style=\"font-family:Cambria;font-size:17px;\">proof for you</div>", "<div style=\"font-family:Cambria;font-size:17px;\">weakest form of faith</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The 23rd Hadith of al-Nawawi's collection states that 'Purification is half of faith'. Therefore, purification is referred to as 'half of faith'.</div>", "topic": "HADITH : THE STUDY OF THE ARABIC TEXTS OF THE FOLLOWING AHADITH FROMAN-NAWAWI’S COLLECTION: 1,3,5,6,7,9,10,11,12,13,15,16, 18,19,21,22,25,27,34, AND 41"}, {"id": "objective>IRK>1992>15", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following statements completes the Hadith which says 'He is not a faithful Muslim who eats to his fill while . . .'</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">he is on a journey in the month of Ramadan</div>", "<div style=\"font-family:Cambria;font-size:17px;\">his neighbour is hungry beside of him</div>", "<div style=\"font-family:Cambria;font-size:17px;\">his family is sleeping hungry </div>", "<div style=\"font-family:Cambria;font-size:17px;\">his colleagues are waiting for him</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The Hadith completes as 'He is not a faithful Muslim who eats to his fill while his neighbour is hungry beside of him'. This Hadith emphasizes the importance of caring for one's neighbours in Islam.</div>", "topic": "MORAL LESSONS IN THE GLORIOUS QUR’AN AND HADITH : DIGNITY OF LABOUR (Q.62:10) (Q.78:11) HADITH FROM BUKHARI AND IBNMAJAH: “THAT ONE OF YOU TAKES HIS ROPE…….” “NEVER HAS ANYONE OF YOU EATEN…..”."}, {"id": "objective>IRK>1992>16", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A Hadith with uninterrupted chain of authorities traced back to the Prophet Muhammad (S.A.W.) himself is described as </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Mutawatir </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Mawquf </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Maqtu</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Muttasil-marfu</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A Hadith with uninterrupted chain of authorities traced back to the Prophet Muhammad (S.A.W.) himself is described as Mutawātir Hadith.</div>", "topic": "HADITH : AUTHENTICATION OF HADITH"}, {"id": "objective>IRK>1992>17", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following terms is most closely related to divorce?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">zawaj</div>", "<div style=\"font-family:Cambria;font-size:17px;\">' iddah</div>", "<div style=\"font-family:Cambria;font-size:17px;\">mahr </div>", "<div style=\"font-family:Cambria;font-size:17px;\">idrar</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">'Iddah' is the term most closely related to divorce in Islamic law. It refers to the waiting period that a woman must observe after the death of her spouse or after a divorce, during which she may not marry another man.</div>", "topic": "FAMILY MATTERS : DIVORCE"}, {"id": "objective>IRK>1992>18", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Kaffarah (major expiation) is compulsory upon a husband who revokes </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Li an</div>", "<div style=\"font-family:Cambria;font-size:17px;\">zihar </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Ila</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Khul</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Kaffarah (major expiation) is compulsory upon a husband who revokes 'zihar'. 'Zihar' is a pre-Islamic Arabian form of divorce where a man says to his wife: 'You are to me as the back of my mother'. This was considered a major sin, and the expiation (kaffarah) for it is described in the Quran.</div>", "topic": "FAMILY MATTERS : DIVORCE"}, {"id": "objective>IRK>1992>19", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Part of the wisdom in instituting the 'iddah in marriage is to </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">make the marriage stable </div>", "<div style=\"font-family:Cambria;font-size:17px;\">enable the wife to settle down </div>", "<div style=\"font-family:Cambria;font-size:17px;\">give chance for reconciliation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">prevent the woman from marrying</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">'Iddah' is a waiting period that a woman must observe after the death of her spouse or after a divorce, during which she may not marry another man. Its primary purpose is to allow for reconciliation between the couple and to determine whether the woman is pregnant, which would impact inheritance and other legal matters.</div>", "topic": "FAMILY MATTERS : DIVORCE"}, {"id": "objective>IRK>1992>20", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Zakah rate to be paid on money is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">2</td><td style=\"text-align:center;\">1<hr size=\"1\" />4</td><td style=\"text-align:center;\">%</td></tr></table></div></div>", "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">3</td><td style=\"text-align:center;\">1<hr size=\"1\" />2</td><td style=\"text-align:center;\">%</td></tr></table></div></div>", "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">4</td><td style=\"text-align:center;\">1<hr size=\"1\" />2</td><td style=\"text-align:center;\">%</td></tr></table></div></div>", "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">5</td><td style=\"text-align:center;\">1<hr size=\"1\" />2</td><td style=\"text-align:center;\">%</td></tr></table></div></div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The Zakah rate to be paid on money is: <br/>  <br/> 2.5% (or 1/40) of the total amount of money held for one full lunar year (ḥawl), provided it reaches or exceeds the niṣāb (minimum threshold).</div>", "topic": "IBADAT AND THEIR TYPES : ZAKAH"}, {"id": "objective>IRK>1992>21", "question": "<div style=\"font-family:Cambria;font-size:17px;\">What percentage of the estate of a late childless wife can the Muslim husband inherit?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">1/2</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1/3</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1/4</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1/6</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">According to Islamic inheritance law, if a wife dies without children, her husband inherits 1/2 of her estate. This is based on the Quranic verse 4:12 which states 'In what your wives leave, your share is a half if they leave no child...'</div>", "topic": "FAMILY MATTERS : INHERITANCE"}, {"id": "objective>IRK>1992>22", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The money given out to a woman at the time of contracting her marriage is known as </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">al-Mahar</div>", "<div style=\"font-family:Cambria;font-size:17px;\">al-Zakah</div>", "<div style=\"font-family:Cambria;font-size:17px;\">al-Jizyyah</div>", "<div style=\"font-family:Cambria;font-size:17px;\">al-Ujrah</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The money given out to a woman at the time of contracting her marriage is known as al-Mahar.</div>", "topic": "FAMILY MATTERS : MARRIAGE"}, {"id": "objective>IRK>1992>23", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The waiting period for a divorced woman is termed </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">id</div>", "<div style=\"font-family:Cambria;font-size:17px;\">waqt</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Sa ah </div>", "<div style=\"font-family:Cambria;font-size:17px;\">'iddah</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The waiting period for a divorced woman in Islam is termed 'Iddah'. This period is to ensure that the woman is not pregnant, but is also a period of mourning and reflection.</div>", "topic": "FAMILY MATTERS : DIVORCE"}, {"id": "objective>IRK>1992>24", "question": "<div style=\"font-family:Cambria;font-size:17px;\">When Prophet Muhammad (S.A.W.) led the Muslims in a triumphant entry into Makkah, all Makkans were assured of their safety if they entered the sacred mosque, remained indoors in their homes or </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">entered the house of Abu Sufyan</div>", "<div style=\"font-family:Cambria;font-size:17px;\">prostrated themselves before Muhammad (S.A.W.)</div>", "<div style=\"font-family:Cambria;font-size:17px;\">surrendered all their belongings </div>", "<div style=\"font-family:Cambria;font-size:17px;\">freed all detained Muslims </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">When Prophet Muhammad (S.A.W.) led the Muslims in a triumphant entry into Makkah, he assured all Makkans of their safety if they entered the sacred mosque, remained indoors in their homes or entered the house of Abu Sufyan. Abu Sufyan was a leader of the Quraysh tribe who later converted to Islam. The Prophet's assurance was a gesture of peace and forgiveness.</div>", "topic": "THE LIFE OF PROPHET MUHAMMAD (SAW) : THE TREATY OF AL-HUDAIBIYYAH AND THE CONQUEST OF MAKKAH"}, {"id": "objective>IRK>1992>25", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The Prophet (S.A.W.) ordered some of the Muslims to emigrate to Abyssina</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">in order to be far away from Makkah</div>", "<div style=\"font-family:Cambria;font-size:17px;\">because he wanted them to preach Islam to the Negus </div>", "<div style=\"font-family:Cambria;font-size:17px;\">in order to go beyonf the reach of their persecutors </div>", "<div style=\"font-family:Cambria;font-size:17px;\">because Bilal, one of the converted Muslims was an Alyssinian</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The Prophet (S.A.W.) ordered some of the Muslims to emigrate to Abyssinia in order to go beyond the reach of their persecutors. At that time, Muslims were being persecuted in Makkah, and Abyssinia (modern-day Ethiopia) was known for its just Christian king, Negus, who gave them protection.</div>", "topic": "EARLY CONTACT OF ISLAM WITH AFRICA : HIJRAH TO ABYSSINIA"}, {"id": "objective>IRK>1992>26", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The monogamous life of Prophet Muhammad (S.A.W.) lasted for </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">5 years </div>", "<div style=\"font-family:Cambria;font-size:17px;\">10 years </div>", "<div style=\"font-family:Cambria;font-size:17px;\">13 years </div>", "<div style=\"font-family:Cambria;font-size:17px;\">25 years </div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The monogamous life of Prophet Muhammad (S.A.W.) lasted for 25 years. During this period, he was married only to Khadijah until her death.</div>", "topic": "THE LIFE OF PROPHET MUHAMMAD (SAW) : HIS BIRTH AND EARLY LIFE"}, {"id": "objective>IRK>1992>27", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The Truce of al-Hudaybiyyah included terms such as </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">payment of reparations to the Makkans by the Ummah</div>", "<div style=\"font-family:Cambria;font-size:17px;\">prevention of Muslims from entering Makkah until ten years later </div>", "<div style=\"font-family:Cambria;font-size:17px;\">the observance by both parties of a ten year period of peace </div>", "<div style=\"font-family:Cambria;font-size:17px;\">the encouragement of the Makkans to join the Muslims in al-Madinah</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The Truce of al-Hudaybiyyah included terms such as the observance by both parties of a ten year period of peace. This treaty was between the Prophet Muhammad, representing the state of Medina, and the Quraysh tribe of Mecca.</div>", "topic": "THE LIFE OF PROPHET MUHAMMAD (SAW) : THE TREATY OF AL-HUDAIBIYYAH AND THE CONQUEST OF MAKKAH"}, {"id": "objective>IRK>1992>28", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following led away a section of the Muslims army when preparations were on for the battle of Uhud?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Abu Lahb</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Abu Jahl</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Abdullah b. Ubayy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Abudullah b. Awwam</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Abdullah b. Ubayy led away a section of the Muslim army when preparations were on for the battle of Uhud. He was a leader of the hypocrites (munafiqun) who outwardly professed Islam while inwardly concealing disbelief and actively worked against the Muslim community.</div>", "topic": "THE LIFE OF PROPHET MUHAMMAD (SAW) : THE BATTLES OF BADR, UHUD AND KHANDAQ: CAUSES AND EFFECTS"}, {"id": "objective>IRK>1992>29", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following battles resulted in more people being converted to Islam?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Uhud</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Badr </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Hunayn</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Khandaq</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The Battle of Hunayn resulted in more people being converted to Islam. After the conquest of Mecca, the tribes of Hawazin and Thaqif posed a threat to the Muslims. The Prophet Muhammad (PBUH) and the Muslims fought against them in the Battle of Hunayn and emerged victorious. Many captives were taken during this battle, who were later released and converted to Islam.</div>", "topic": "THE LIFE OF PROPHET MUHAMMAD (SAW) : THE BATTLES OF BADR, UHUD AND KHANDAQ: CAUSES AND EFFECTS"}, {"id": "objective>IRK>1992>30", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Muhammad resulullah in the kalimatu sh-shahadah means that Muhammad (S.A.W.) is to Allah a </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">prophet</div>", "<div style=\"font-family:Cambria;font-size:17px;\">messenger </div>", "<div style=\"font-family:Cambria;font-size:17px;\">servant</div>", "<div style=\"font-family:Cambria;font-size:17px;\">slave</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In the Shahada, 'Muhammad resulullah' means 'Muhammad is the messenger of Allah'. The term 'resul' in Arabic translates to 'messenger'. This is a fundamental belief in Islam that Muhammad (PBUH) is not just a prophet, but the final messenger of Allah.</div>", "topic": "TAWHID AND FIQH : KALIMATUSH-SHAHADAH"}, {"id": "objective>IRK>1992>31", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Defrauding by giving too little and asking for too much is condemned in surah</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">at-Tin</div>", "<div style=\"font-family:Cambria;font-size:17px;\">at-Tatfif</div>", "<div style=\"font-family:Cambria;font-size:17px;\">al-maun</div>", "<div style=\"font-family:Cambria;font-size:17px;\">at-Takathur</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The practice of defrauding by giving too little and asking for too much is condemned in Surah al-Mutaffifin (also known as at-Tatfif). The Surah takes its name from the word Tatfif in the first verse. This word is used to express the fraudulent act of giving less in measure and weight.</div>", "topic": "ISLAMIC ECONOMIC SYSTEM : AT-TATFIF"}, {"id": "objective>IRK>1992>32", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Standing on 'Arafat is a major difference between Hajj and </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Qiran</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Tamattu</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Ifrad </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Umrah</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The major difference between Hajj and Umrah is the standing on 'Arafat (also known as Wuquf), which is considered the most important part of the Hajj pilgrimage. This ritual is not part of the Umrah. Umrah can be performed at any time of the year, unlike Hajj which has specific dates according to the Islamic calendar.</div>", "topic": "IBADAT AND THEIR TYPES : HAJJ"}, {"id": "objective>IRK>1992>33", "question": "<div style=\"font-family:Cambria;font-size:17px;\">When you read loudly while praying Zuhr in one of the rak at, you are expected to </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">repeat your prayer </div>", "<div style=\"font-family:Cambria;font-size:17px;\">make a qabli sujud</div>", "<div style=\"font-family:Cambria;font-size:17px;\">make a ba di sujud </div>", "<div style=\"font-family:Cambria;font-size:17px;\">recite the qunut    </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">When you read loudly while praying Zuhr in one of the rak at, you are expected to make a ba di sujud.</div>", "topic": "IBADAT AND THEIR TYPES : SALAH"}, {"id": "objective>IRK>1992>34", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Those to benefit from the proceeds of Zakah include </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">old men and women</div>", "<div style=\"font-family:Cambria;font-size:17px;\">officers employed to administer it </div>", "<div style=\"font-family:Cambria;font-size:17px;\">under-aged children</div>", "<div style=\"font-family:Cambria;font-size:17px;\">self-employed low-income earners </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Zakah is a form of alms-giving treated in Islam as a religious obligation or tax, which, by Quranic ranking, is next after prayer in importance. The proceeds of Zakah are meant to benefit certain categories of people, including those employed to administer it. This is stated in Surah At-Tawbah (9:60).</div>", "topic": "IBADAT AND THEIR TYPES : ZAKAH"}, {"id": "objective>IRK>1992>35", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The last sentence in the Talbiyah is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Labbayka Allahuma labbyka </div>", "<div style=\"font-family:Cambria;font-size:17px;\">La sharika laka</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Innal Hamda wa n-Ni mata laka wal-mulk</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Labbayka la sharika laka labbayka </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The last sentence in the Talbiyah is La sharika laka.</div>", "topic": "TAWHID AND FIQH : KALIMATUSH-SHAHADAH"}, {"id": "objective>IRK>1992>36", "question": "<div style=\"font-family:Cambria;font-size:17px;\">One of the conditions for performing the Hajj is the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">ability to read the Quran and write the Quranic verses </div>", "<div style=\"font-family:Cambria;font-size:17px;\">religiousness of the person</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ability to finance the journey</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ability to travel by air</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">One of the conditions for performing the Hajj is the ability to finance the journey. This is because Hajj is only obligatory for adult Muslims who are physically and financially capable of undertaking the journey, and can support their family during their absence.</div>", "topic": "IBADAT AND THEIR TYPES : HAJJ"}, {"id": "objective>IRK>1992>37", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A Muslim who joins the Imam while he is rising from the last ruku of the last rakah has to </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">repeat the raka as if he did not join in it </div>", "<div style=\"font-family:Cambria;font-size:17px;\">complete the remaining except the last rakah</div>", "<div style=\"font-family:Cambria;font-size:17px;\">continue the prayer and thereafter observe all the rakat</div>", "<div style=\"font-family:Cambria;font-size:17px;\">end up the prayer with the Imam</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A Muslim who joins the Imam while he is rising from the last ruku of the last rakah has to continue the prayer and thereafter observe all the rakat.</div>", "topic": "IBADAT AND THEIR TYPES : SALAH"}, {"id": "objective>IRK>1992>38", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In which verse of the Quran are woman directed to dress modestly?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">5:3</div>", "<div style=\"font-family:Cambria;font-size:17px;\">24:31</div>", "<div style=\"font-family:Cambria;font-size:17px;\">55:10</div>", "<div style=\"font-family:Cambria;font-size:17px;\">112:4</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In the Quran, women are directed to dress modestly in Surah An-Nur (24:31). This verse instructs women to guard their private parts and not display their adornment except what is apparent, and to draw their veils over their chests.</div>", "topic": "MORAL LESSONS IN THE GLORIOUS QUR'AN AND HADITH : BEHAVIOUR AND MODESTY IN DRESSING"}, {"id": "objective>IRK>1992>39", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Superstitious beliefs are not compatible with Islamic principles because they are </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">related to culture and tradition</div>", "<div style=\"font-family:Cambria;font-size:17px;\">usually contrary to the concept of iman</div>", "<div style=\"font-family:Cambria;font-size:17px;\">often found among non-Arabs </div>", "<div style=\"font-family:Cambria;font-size:17px;\">encouraged by other scriptured religions </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Superstitious beliefs are not compatible with Islamic principles because they are usually contrary to the concept of iman. Iman in Islam refers to faith or belief in the six articles of faith: belief in God, His angels, His books, His messengers, the Day of Judgment, and destiny. Superstitious beliefs often involve attributing events or outcomes to supernatural forces or luck, which contradicts the Islamic belief in the oneness of God and His control over all events.</div>", "topic": "TAWHID AND FIQH : GENERAL PRACTICES WHICH ARE INCOMPATIBLE WITH ISLAMIC PRINCIPLES OF TAWHID"}, {"id": "objective>IRK>1992>40", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Prophet Musa (A.S.) went to the sacred valley where he </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">received divine directives </div>", "<div style=\"font-family:Cambria;font-size:17px;\">destroyed the golden calf </div>", "<div style=\"font-family:Cambria;font-size:17px;\">reared sheep and goats </div>", "<div style=\"font-family:Cambria;font-size:17px;\">killed the Egyptian</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Prophet Musa (A.S.) went to the sacred valley where he received divine directives. This is a reference to the event in the Quran where Prophet Musa (Moses) was called by God at Mount Sinai and given the Ten Commandments.</div>", "topic": "ARTICLE OF FAITH : HIS PROPHETS: ULUL-AZMI"}, {"id": "objective>IRK>1992>41", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Kalimatu sh-shahadah is the first pillar of Islam, the second being </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">pilgrimage to Makkah</div>", "<div style=\"font-family:Cambria;font-size:17px;\">payment of Zakah</div>", "<div style=\"font-family:Cambria;font-size:17px;\">fasting in the month of Ramadan</div>", "<div style=\"font-family:Cambria;font-size:17px;\">observance of the five daily prayers </div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Kalimatu sh-shahadah is the first pillar of Islam, the second being observance of the five daily prayers. The five pillars of Islam are the basic acts of worship that every Muslim is required to perform. They include the shahadah (declaration of faith), salah (prayer), zakah (charity), sawm (fasting during Ramadan), and hajj (pilgrimage to Mecca).</div>", "topic": "TAWHID AND FIQH : KALIMATUSH-SHAHADAH"}, {"id": "objective>IRK>1992>42", "question": "<div style=\"font-family:Cambria;font-size:17px;\">What is ijma in Islamic law?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Consensus of opinion</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Analogical deduction</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Differences of opinion</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Minority opinion</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Ijma in Islamic law refers to the consensus of opinion. It is one of the four main sources of Islamic law, along with the Quran, Hadith, and Qiyas (analogical reasoning). Ijma represents the agreement of Muslim scholars on a particular legal issue.</div>", "topic": "SOURCES AND SCHOOLS OF LAW : THE FOUR MAJOR SOURCES THE QUR'AN, SUNNAH, IJMA AND QIYAS"}, {"id": "objective>IRK>1992>43", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The sources of the Shari ah include </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Quran Hadith and common law </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Hadith Qiyas and parliamentary proceedings </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Qiyas, Tawil and Falsafah</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Quran, Ijana and Qiyas </div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The sources of the Shari'ah include Quran, Ijma (consensus of opinion), and Qiyas (analogical reasoning). These are the primary sources used in the formulation of Islamic law. The Quran is the holy book of Islam, Ijma represents the agreement of Muslim scholars on a particular legal issue, and Qiyas is the process of deductive analogy in which the teachings of the Hadith are compared and contrasted with those of the Quran, in order to apply a known injunction to a new circumstance and create a new injunction.</div>", "topic": "SOURCES AND SCHOOLS OF LAW : THE FOUR MAJOR SOURCES THE QUR'AN, SUNNAH, IJMA AND QIYAS"}, {"id": "objective>IRK>1992>44", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following are secondary sources of the Shari ah?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Quran and Hadith</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Ijma and Qiyas </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Quran and Qiyas </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Qiyas and Hadith</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The Shari'ah, or Islamic law, is derived from four main sources. The primary sources are the Quran and the Hadith. The secondary sources are Ijma (consensus of scholars) and Qiyas (analogical deduction). Therefore, the correct answer is 'Ijma and Qiyas'.</div>", "topic": "SOURCES AND SCHOOLS OF LAW : THE FOUR MAJOR SOURCES THE QUR'AN, SUNNAH, IJMA AND QIYAS"}, {"id": "objective>IRK>1992>45", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Imam Ash-shafii studied under two of his predecessors. These are </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Abu Hurayrah and Malik</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Malik and Abu Hanifah</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Abu Hanifah and Umar</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Umar and Abu Bakr</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Imam Ash-Shafi'i, one of the four great Imams of Islamic Jurisprudence, studied under Imam Malik and Imam Muhammad ibn al-Hasan al-Shaybani, who was a student of Imam Abu Hanifah. Therefore, the correct answer is 'Malik and Abu Hanifah'.</div>", "topic": "SOURCES AND SCHOOLS OF LAW : THE FOUR SUNNI SCHOOLS OF LAW"}, {"id": "objective>IRK>1992>46", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The earliest written records of West African history were written in Arabic because </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">West Africa was colonized by the Arabs </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Arabic was the first written language which West Africans came in contact with </div>", "<div style=\"font-family:Cambria;font-size:17px;\">several Arabic schools existed in West African ashortly after the advent of Islam</div>", "<div style=\"font-family:Cambria;font-size:17px;\">all rulers of West Africa had embraced Islam</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The earliest written records of West African history were written in Arabic because several Arabic schools existed in West African ashortly after the advent of Islam.</div>", "topic": "EARLY CONTACT OF ISLAM WITH AFRICA : THE ROLE OF TRADERS, TEACHERS, PREACHERS, MURABITUN, SUFI ORDERS AND MUJADDIDUN TO THE SPREAD OF ISLAM IN WEST AFRICA."}, {"id": "objective>IRK>1992>47", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The first Islamic university established in West Africa is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Aghades </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Sankore </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Timbuktu</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Gao</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The first Islamic university established in West Africa is Timbuktu.</div>", "topic": "CONTRIBUTIONS OF ISLAM TO EDUCATION : INTELLECTUAL ACTIVITIES OF ISLAM IN WEST AFRICA (DEVELOPMENT OFWRITTEN HISTORY IN ARABIC AND THE ESTABLISHMENT OF SANKORE UNIVERSITY)"}, {"id": "objective>IRK>1992>48", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The initial spread of Islam in West Africa can be described as generally</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">rapid and systematic </div>", "<div style=\"font-family:Cambria;font-size:17px;\">rapid and thorough</div>", "<div style=\"font-family:Cambria;font-size:17px;\">slow but peaceful</div>", "<div style=\"font-family:Cambria;font-size:17px;\">peaceful and systematic</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The initial spread of Islam in West Africa can be described as generally peaceful and systematic.</div>", "topic": "EARLY CONTACT OF ISLAM WITH AFRICA : THE ROLE OF TRADERS, TEACHERS, PREACHERS, MURABITUN, SUFI ORDERS AND MUJADDIDUN TO THE SPREAD OF ISLAM IN WEST AFRICA."}, {"id": "objective>IRK>1992>49", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The jurist who made Tasawwuf compatible with the Shari ah was </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">ibn Sina</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ibn Khaldun</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Ar-Razi</div>", "<div style=\"font-family:Cambria;font-size:17px;\">al-Ghazali</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Al-Ghazali is the jurist who made Tasawwuf (Sufism) compatible with the Shari'ah (Islamic law). He was a Persian theologian, jurist, and mystic who is credited with reconciling the mystical aspects of Islam (Sufism) with the legalistic aspects (Shari'ah).</div>", "topic": "CONTRIBUTIONS OF ISLAM TO EDUCATION : THE LIVES AND CONTRIBUTIONS OF IBN SINA, AL-GHAZALI, IBN RUSHDI, AR-RAZIO AND IBN KHALDUN TO EDUCATION."}, {"id": "objective>IRK>1992>50", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The first Umayyad caliph was </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">'Abdullah b. Umar</div>", "<div style=\"font-family:Cambria;font-size:17px;\">'Umar b. Abdul Aziz</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Walid b. Yazid </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Mu awiya b. Abi Sufyan</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The first Umayyad caliph was Mu'awiya b. Abi Sufyan. The Umayyad dynasty was the first great Muslim dynasty to rule the empire of the Caliphate (661–750 CE), sometimes referred to as the Arab kingdom.</div>", "topic": "THE LIFE OF PROPHET MUHAMMAD (SAW) : ADMINISTRATION OF THE UMMAH AND THE ROLE OF THE MOSQUE (Q.3:159) (Q.4:58 AND 135)"}];
